import React, { useState } from 'react';
import './index.css';

// Projects Data (No scores, all have live links)
const PROJECTS = [
  {
    id: '01', name: 'Vivasayi Farm App', date: '24 Aug 2025',
    live: 'https://vivasayi-wheat.vercel.app',
    tech: ['Next.js', 'Supabase'], color: 'var(--color-green)'
  },
  {
    id: '02', name: 'Havan Transit Engine', date: '12 Sep 2025',
    live: 'https://havan-bus-booking-engine.vercel.app',
    tech: ['Django', 'React'], color: 'var(--color-yellow)'
  },
  {
    id: '03', name: 'Havan Vision AI Chat', date: '04 Oct 2025',
    live: 'https://github.com/Madhavan-dev18/havan-vision',
    tech: ['Flask', 'LLaMA'], color: 'var(--color-blue)'
  },
  {
    id: '04', name: 'Havan Stream HLS', date: '18 Nov 2025',
    live: 'https://github.com/Madhavan-dev18/havan-stream',
    tech: ['Vite', 'Django'], color: 'var(--color-pink)'
  }
];

// Stats Data
const STATS = [
  { title: 'Live Deployments', value: '4/4', percent: '100%', color: 'var(--color-green)', date: 'Ongoing' },
  { title: 'CVEs Patched', value: '3/3', percent: '100%', color: 'var(--color-yellow)', date: 'Verified' },
  { title: 'Test Coverage', value: '73 Passing', percent: '85%', color: 'var(--color-blue)', date: 'CI/CD' }
];

// Experience Data
const EXP = [
  { date: 'May 2025', title: 'Python Developer Intern', desc: 'Built Django bus reservation system with SQLite and row-level locking.', label: 'NextGen Tech', btnColor: 'var(--color-purple)' },
  { date: '2023 - 2026', title: 'B.Sc. Computer Science', desc: 'Thiruvalluvar University. Active placement-season candidate.', label: 'KMG College', btnColor: 'var(--color-blue)' }
];

// Skills Data
const SKILLS = [
  { category: 'Languages', items: ['Python', 'JavaScript', 'HTML/CSS', 'SQL'], color: 'var(--color-blue)' },
  { category: 'Frameworks', items: ['React', 'Next.js', 'Django', 'Flask'], color: 'var(--color-green)' },
  { category: 'Tools', items: ['Git', 'Docker', 'Supabase', 'AWS'], color: 'var(--color-purple)' }
];

export default function App() {
  const [activeTab, setActiveTab] = useState('dashboard');

  const renderPageContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="dashboard-grid">
            <div className="left-panel">
              <div className="stats-row">
                {STATS.map((stat, i) => (
                  <div className="stat-card" key={i}>
                    <div className="stat-title">{stat.title}</div>
                    <div className="stat-progress-bar">
                      <div className="stat-progress-fill" style={{width: stat.percent, backgroundColor: stat.color}}></div>
                    </div>
                    <div className="stat-bottom">
                      <span>{stat.date}</span>
                      <span style={{color: '#111'}}>{stat.percent}</span>
                    </div>
                  </div>
                ))}
              </div>

              <div>
                <div className="list-header">
                  <div className="list-tab active">Recent Projects</div>
                </div>

                <div className="project-list">
                  {PROJECTS.slice(0, 2).map((proj, i) => (
                    <div className="project-row" key={i}>
                      <div className="project-icon">✓</div>
                      <div className="project-name">{proj.name}</div>
                      <div className="project-tech">
                        {proj.tech.map(t => <span className="tech-tag" style={{backgroundColor: proj.color}} key={t}>{t}</span>)}
                      </div>
                      <div className="project-date">{proj.date}</div>
                      <a href={proj.live} target="_blank" rel="noreferrer" className="project-live">LIVE ↗</a>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="right-panel">
              <div className="side-tabs">
                <button className="side-tab active">Recent Experience</button>
              </div>

              {EXP.slice(0, 1).map((e, i) => (
                <div className="side-card" key={i}>
                  <div className="side-card-label">
                    <span style={{fontSize: '16px'}}>📅</span> {e.date}
                  </div>
                  <div className="side-card-title">{e.title}</div>
                  <div className="side-card-desc">{e.desc}</div>
                  <div className="side-card-btn" style={{backgroundColor: e.btnColor}}>{e.label}</div>
                </div>
              ))}
            </div>
          </div>
        );

      case 'projects':
        return (
          <div className="page-section">
            <div className="project-grid">
              {PROJECTS.map((proj, i) => (
                <div className="project-card-large" key={i}>
                  <div className="project-card-header">
                    <div className="project-icon-large" style={{backgroundColor: proj.color}}>✦</div>
                    <div className="project-date">{proj.date}</div>
                  </div>
                  <div className="project-card-title">{proj.name}</div>
                  <div className="project-tech">
                    {proj.tech.map(t => <span className="tech-tag" style={{backgroundColor: proj.color}} key={t}>{t}</span>)}
                  </div>
                  <a href={proj.live} target="_blank" rel="noreferrer" className="btn-primary mt-4" style={{width: 'fit-content', marginTop: '24px'}}>View Live ↗</a>
                </div>
              ))}
            </div>
          </div>
        );

      case 'experience':
        return (
          <div className="dashboard-grid">
            <div className="left-panel">
              <h2 className="section-title">Timeline</h2>
              {EXP.map((e, i) => (
                <div className="side-card mb-4" key={i}>
                  <div className="side-card-label">
                    <span style={{fontSize: '16px'}}>📅</span> {e.date}
                  </div>
                  <div className="side-card-title">{e.title}</div>
                  <div className="side-card-desc">{e.desc}</div>
                  <div className="side-card-btn" style={{backgroundColor: e.btnColor}}>{e.label}</div>
                </div>
              ))}
            </div>
            <div className="right-panel">
              <h2 className="section-title">Technical Skills</h2>
              <div className="skills-container">
                {SKILLS.map((skillGroup, i) => (
                  <div className="skill-group" key={i}>
                    <div className="skill-category">{skillGroup.category}</div>
                    <div className="skill-items">
                      {skillGroup.items.map(skill => (
                        <span className="skill-tag" style={{borderColor: skillGroup.color, backgroundColor: skillGroup.color + '22'}} key={skill}>{skill}</span>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        );

      case 'repos':
        return (
          <div className="page-section empty-state">
            <div className="empty-icon" style={{backgroundColor: 'var(--color-green)'}}>◳</div>
            <h2>GitHub Repositories</h2>
            <p style={{color: 'var(--fg-muted)', marginBottom: '24px'}}>Connect your GitHub API to view repositories here.</p>
            <a href="https://github.com/Madhavan-dev18" target="_blank" rel="noreferrer" className="btn-primary" style={{margin: '0 auto'}}>View GitHub Profile</a>
          </div>
        );

      case 'contact':
        return (
          <div className="page-section contact-section">
            <div className="contact-card">
              <h2>Get in Touch</h2>
              <p>I'm always open to discussing new projects, creative ideas, or opportunities to be part of your visions.</p>

              <div className="contact-details">
                <div className="contact-item">
                  <span className="contact-icon">✉</span>
                  <a href="mailto:madhavantt2017@gmail.com">madhavantt2017@gmail.com</a>
                </div>
                <div className="contact-item">
                  <span className="contact-icon">🔗</span>
                  <a href="https://github.com/Madhavan-dev18" target="_blank" rel="noreferrer">github.com/Madhavan-dev18</a>
                </div>
              </div>

              <button className="btn-primary" style={{marginTop: '24px'}} onClick={() => window.location.href="mailto:madhavantt2017@gmail.com"}>
                Send an Email
              </button>
            </div>
          </div>
        );

      default:
        return <div>Select a tab</div>;
    }
  };

  return (
    <div className="dashboard-layout">

      {/* SIDEBAR */}
      <div className="sidebar">
        <div className="brand">
          MADHAVAN S <div className="brand-dot"></div>
        </div>

        <div className="nav-group">
          <div className="nav-label">Navigation</div>
          <div className={`nav-item ${activeTab === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveTab('dashboard')}>
            <div><span className="nav-icon">✦</span> Dashboard</div>
            <div className="nav-badge">04</div>
          </div>
          <div className={`nav-item ${activeTab === 'projects' ? 'active' : ''}`} onClick={() => setActiveTab('projects')}>
            <div><span className="nav-icon">▢</span> Projects</div>
          </div>
          <div className={`nav-item ${activeTab === 'experience' ? 'active' : ''}`} onClick={() => setActiveTab('experience')}>
            <div><span className="nav-icon">▤</span> Experience</div>
          </div>
          <div className={`nav-item ${activeTab === 'repos' ? 'active' : ''}`} onClick={() => setActiveTab('repos')}>
            <div><span className="nav-icon">◳</span> Repositories</div>
            <div className="nav-badge" style={{backgroundColor: 'var(--color-green)'}}>08</div>
          </div>
          <div className={`nav-item ${activeTab === 'contact' ? 'active' : ''}`} onClick={() => setActiveTab('contact')}>
            <div><span className="nav-icon">✉</span> Contact</div>
          </div>
        </div>

        <div className="sidebar-bottom">
          <div className="avatar"></div>
          <div className="user-info">
            <span className="user-name">Madhavan S</span>
            <span className="user-role">Full-Stack Dev</span>
          </div>
        </div>
      </div>

      {/* MAIN CONTENT */}
      <div className="main-content">

        {/* TOP NAV */}
        <div className="top-nav">
          <h1 className="page-title" style={{textTransform: 'capitalize'}}>{activeTab}</h1>
          <div className="top-actions">
            <span className="action-icon">🔍</span>
            <span className="action-icon">🔔</span>
            <button className="btn-primary" onClick={() => window.location.href="mailto:madhavantt2017@gmail.com"}>
              <span>+</span> Hire Me
            </button>
          </div>
        </div>

        {/* DYNAMIC PAGE CONTENT */}
        {renderPageContent()}
      </div>

    </div>
  );
}
